const allItems = $input.all();
const now = new Date();
const cutoff48h = new Date(now.getTime() - 48 * 60 * 60 * 1000);
const cutoff72h = new Date(now.getTime() - 72 * 60 * 60 * 1000);

function parseDate(j) {
  for (const f of [j.pubDate, j.isoDate, j.date, j.published]) {
    if (f) { const d = new Date(f); if (!isNaN(d.getTime())) return d; }
  }
  return new Date(0);
}

function relevanceScore(text) {
  const t = (text || '').toLowerCase();
  const strong = ['enterprise', 'corporativo', 'negocio', 'automacao', 'agente', 'agentic', 'workflow', 'investimento', 'aquisicao', 'governanca', 'produtividade', 'roi', 'gestao', 'estrategia'];
  const weak = ['celular', 'jogo', 'game', 'filme', 'celebridade', 'rumor', 'vazamento', 'gadget'];
  let score = 0;
  strong.forEach(function(kw) { if (t.includes(kw)) score += 3; });
  weak.forEach(function(kw) { if (t.includes(kw)) score -= 5; });
  return score;
}

const seen = new Set();
let candidates = allItems
  .map(function(item) {
    const j = item.json || {};
    const date = parseDate(j);
    const text = [j.title, j.contentSnippet, j.summary, j.description].join(' ');
    return Object.assign({}, j, { _date: date, _score: relevanceScore(text) });
  })
  .filter(function(i) { return i._date >= cutoff48h; });

if (candidates.length < 3) {
  candidates = allItems
    .map(function(item) {
      const j = item.json || {};
      const date = parseDate(j);
      const text = [j.title, j.contentSnippet, j.summary, j.description].join(' ');
      return Object.assign({}, j, { _date: date, _score: relevanceScore(text) });
    })
    .filter(function(i) { return i._date >= cutoff72h; });
}

candidates = candidates
  .filter(function(i) {
    const key = String(i.title || '').toLowerCase().substring(0, 80);
    if (!key || seen.has(key)) return false;
    seen.add(key);
    return true;
  })
  .sort(function(a, b) { return (b._score - a._score) || (b._date - a._date); })
  .slice(0, 5);

if (candidates.length === 0) {
  throw new Error('Nenhuma noticia encontrada nas ultimas 72h. Verificar feeds RSS.');
}

const noticias = candidates.map(function(item, idx) {
  const title = String(item.title || 'Sem titulo').replace(/\s+-\s+[^-]+$/, '').trim();
  const summary = String(item.contentSnippet || item.summary || item.description || '')
    .replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim().substring(0, 300);
  return '[' + (idx + 1) + '] ' + title + '\n' + summary;
}).join('\n\n');

return [{ json: { noticias: noticias, total_noticias: candidates.length } }];

const response = $input.first().json;

if (response.error) {
  throw new Error('Erro na API de texto: ' + JSON.stringify(response.error));
}

let content = '';
if (response.choices && response.choices[0] && response.choices[0].message) {
  content = response.choices[0].message.content || '';
}

if (!content || content.length < 50) {
  throw new Error('Post gerado vazio ou muito curto.');
}

const separator = '---IMAGE_PROMPT---';
let post_text = content.trim();
let image_prompt = 'Clean corporate 3D render of glowing neural network nodes connected to organizational chart structures, deep blue and white color palette, professional tech aesthetic, no text, no people, no faces, no logos, photorealistic digital art';

if (content.includes(separator)) {
  const parts = content.split(separator);
  post_text = parts[0].trim();
  const raw_prompt = parts[1] ? parts[1].trim() : '';
  if (raw_prompt.length > 10) image_prompt = raw_prompt;
}

return [{ json: { post_text: post_text, image_prompt: image_prompt } }];

const response = $input.first().json;
const post_text = $('Code - Extrair Texto e Prompt').first().json.post_text;

if (response.error) {
  throw new Error('Erro na API de imagem: ' + JSON.stringify(response.error));
}

const b64 = response.data && response.data[0] ? response.data[0].b64_json : null;
if (!b64) {
  throw new Error('Imagem nao recebida da API. Verifique o no anterior.');
}

if (!post_text || post_text.length < 30) {
  throw new Error('Texto do post invalido ou nao encontrado.');
}

const buffer = Buffer.from(b64, 'base64');
const binaryData = await this.helpers.prepareBinaryData(buffer, 'post.png', 'image/png');

return [{ json: { post_text: post_text }, binary: { data: binaryData } }];

const postText = $('Code - Extrair Imagem').first().json.post_text;
const personId = $('LinkedIn - Get Profile').first().json.sub;
const assetUrn = $('LinkedIn - Register Upload').first().json.value.asset;

if (!personId) throw new Error('Person ID do LinkedIn nao encontrado. Verificar credencial OAuth2 e scope openid/profile.');
if (!assetUrn) throw new Error('Asset URN nao retornado pelo LinkedIn Register Upload. Verificar resposta do no anterior.');
if (!postText || postText.length < 30) throw new Error('Texto do post invalido ou muito curto.');

const payload = {
  author: 'urn:li:person:' + personId,
  lifecycleState: 'PUBLISHED',
  specificContent: {
    'com.linkedin.ugc.ShareContent': {
      shareCommentary: { text: postText },
      shareMediaCategory: 'IMAGE',
      media: [{
        status: 'READY',
        description: { text: 'Imagem gerada por IA' },
        media: assetUrn,
        title: { text: 'IA Hoje' }
      }]
    }
  },
  visibility: {
    'com.linkedin.ugc.MemberNetworkVisibility': 'PUBLIC'
  }
};

return [{ json: { payload: JSON.stringify(payload), person_id: personId, asset_urn: assetUrn } }];
